import os
import numpy as np

working_dir = os.path.join(os.getcwd(), "working")
experiment_data_path = os.path.join(working_dir, "experiment_data.npy")

experiment_data = np.load(experiment_data_path, allow_pickle=True).item()


def safe_float(value):
    try:
        return float(value)
    except Exception:
        return value


def print_metric(label, value):
    if isinstance(value, float):
        print(f"{label}: {value:.6f}")
    else:
        print(f"{label}: {value}")


def get_final_metric(metric_list, key):
    if not metric_list:
        return None
    return metric_list[-1].get(key, None)


def get_best_metric(metric_list, key, mode="max"):
    if not metric_list:
        return None
    values = [entry.get(key) for entry in metric_list if key in entry]
    values = [v for v in values if v is not None]
    if not values:
        return None
    return max(values) if mode == "max" else min(values)


def analyze_dataset(dataset_name, dataset_data):
    print(f"Dataset: {dataset_name}")

    metrics = dataset_data.get("metrics", {})
    losses = dataset_data.get("losses", {})
    stream_details = dataset_data.get("stream_details", {})

    train_metrics = metrics.get("train", [])
    val_metrics = metrics.get("val", [])
    stream_metrics = metrics.get("stream", [])

    train_losses = losses.get("train", [])
    val_losses = losses.get("val", [])

    final_train_accuracy = get_final_metric(train_metrics, "accuracy")
    best_train_accuracy = get_best_metric(train_metrics, "accuracy", mode="max")
    final_validation_accuracy = get_final_metric(val_metrics, "accuracy")
    best_validation_accuracy = get_best_metric(val_metrics, "accuracy", mode="max")

    final_train_loss = get_final_metric(train_losses, "loss")
    best_train_loss = get_best_metric(train_losses, "loss", mode="min")
    final_validation_loss = get_final_metric(val_losses, "loss")
    best_validation_loss = get_best_metric(val_losses, "loss", mode="min")

    if final_train_accuracy is not None:
        print_metric("final train accuracy", safe_float(final_train_accuracy))
    if best_train_accuracy is not None:
        print_metric("best train accuracy", safe_float(best_train_accuracy))
    if final_validation_accuracy is not None:
        print_metric("final validation accuracy", safe_float(final_validation_accuracy))
    if best_validation_accuracy is not None:
        print_metric("best validation accuracy", safe_float(best_validation_accuracy))

    if final_train_loss is not None:
        print_metric("final train loss", safe_float(final_train_loss))
    if best_train_loss is not None:
        print_metric("best train loss", safe_float(best_train_loss))
    if final_validation_loss is not None:
        print_metric("final validation loss", safe_float(final_validation_loss))
    if best_validation_loss is not None:
        print_metric("best validation loss", safe_float(best_validation_loss))

    if stream_details:
        for method_name, method_metrics in stream_details.items():
            if "accuracy" in method_metrics:
                print_metric(
                    f"final stream accuracy ({method_name})",
                    safe_float(method_metrics["accuracy"]),
                )
            if "stream_stability_adjusted_accuracy" in method_metrics:
                print_metric(
                    f"final stream stability adjusted accuracy ({method_name})",
                    safe_float(method_metrics["stream_stability_adjusted_accuracy"]),
                )
            if "adaptation_frequency" in method_metrics:
                print_metric(
                    f"final adaptation frequency ({method_name})",
                    safe_float(method_metrics["adaptation_frequency"]),
                )
            if "latency_seconds" in method_metrics:
                print_metric(
                    f"final latency seconds ({method_name})",
                    safe_float(method_metrics["latency_seconds"]),
                )

    if stream_metrics:
        latest_stream_summary = stream_metrics[-1]
        for key, value in latest_stream_summary.items():
            label = key.replace("_", " ")
            print_metric(f"final {label}", safe_float(value))

    predictions = dataset_data.get("predictions", [])
    ground_truth = dataset_data.get("ground_truth", [])
    if predictions and ground_truth and len(predictions) == len(ground_truth):
        predictions_arr = np.array(predictions)
        ground_truth_arr = np.array(ground_truth)
        stream_prediction_accuracy = float((predictions_arr == ground_truth_arr).mean())
        print_metric("final stored prediction accuracy", stream_prediction_accuracy)

    print()


for dataset_name, dataset_data in experiment_data.items():
    analyze_dataset(dataset_name, dataset_data)
